// src/pages/CustomerDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [workers, setWorkers] = useState([]);

  const [form, setForm] = useState({
    workType: "",
    labourId: "",
    labourName: "",
    location: "",
    date: ""
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver"
  ];

  useEffect(() => {
    getRequests();
  }, []);

  /* ================= GET REQUESTS ================= */

  const getRequests = async () => {

    try {

      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );

      setRequests(res.data);

    } catch (err) {
      console.log(err);
    }
  };

  /* ================= SEARCH WORKERS ================= */

  const searchWorkers = async (workType) => {

    if (!workType) return;

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>
        worker.skills.includes(workType)
      );

      setWorkers(filtered);

    } catch (err) {
      console.log(err);
    }
  };

  /* ================= SEND REQUEST ================= */

  const sendRequest = async () => {

    if (
      !form.workType ||
      !form.labourId ||
      !form.location ||
      !form.date
    ) {
      return alert("Fill all fields");
    }

    try {

      await axios.post(
        "http://localhost:5000/api/request/send",
        {
          customerName: user.name,
          customerId: user._id,
          labourId: form.labourId,
          labourName: form.labourName,
          workType: form.workType,
          location: form.location,
          date: form.date,
          timings: ["9AM - 12PM"],
          status: "Pending"
        }
      );

      alert("Request Sent");

      setForm({
        workType: "",
        labourId: "",
        labourName: "",
        location: "",
        date: ""
      });

      setWorkers([]);

      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  /* ================= ACCEPT / REJECT ================= */

  const updateDecision = async (id, decision) => {

    try {

      await axios.put(
        `http://localhost:5000/api/request/customer-decision/${id}`,
        {
          customerDecision: decision,
          status: decision
        }
      );

      getRequests();

    } catch (err) {
      console.log(err);
    }
  };

  /* ================= FEEDBACK ================= */

  const submitFeedback = async (
    id,
    rating,
    comment
  ) => {

    if (!rating || !comment) {
      return alert("Fill rating and review");
    }

    try {

      await axios.put(
        `http://localhost:5000/api/request/feedback/${id}`,
        {
          rating: Number(rating),
          comment
        }
      );

      getRequests();

      alert("Feedback Submitted");

    } catch (err) {
      console.log(err);
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.wrapper}>

        {/* ================= LEFT PANEL ================= */}

        <div style={styles.card}>

          <h2 style={styles.title}>
            Hire Worker
          </h2>

          {/* WORK TYPE */}

          <select
            style={styles.input}
            value={form.workType}
            onChange={(e) => {

              setForm({
                ...form,
                workType: e.target.value
              });

              searchWorkers(e.target.value);
            }}
          >
            <option value="">
              Select Work
            </option>

            {jobs.map(job => (
              <option key={job}>
                {job}
              </option>
            ))}
          </select>

          {/* WORKER */}

          {workers.length > 0 && (

            <select
              style={styles.input}
              value={form.labourId}
              onChange={(e) => {

                const selectedWorker =
                  workers.find(
                    worker => worker._id === e.target.value
                  );

                setForm({
                  ...form,
                  labourId: selectedWorker._id,
                  labourName: selectedWorker.name
                });
              }}
            >
              <option value="">
                Select Worker
              </option>

              {workers.map(worker => (

                <option
                  key={worker._id}
                  value={worker._id}
                >
                  {worker.name} - {worker.city}
                </option>

              ))}
            </select>
          )}

          {/* LOCATION */}

          <input
            style={styles.input}
            placeholder="Enter Location"
            value={form.location}
            onChange={(e) =>
              setForm({
                ...form,
                location: e.target.value
              })
            }
          />

          {/* DATE */}

          <input
            type="date"
            style={styles.input}
            value={form.date}
            onChange={(e) =>
              setForm({
                ...form,
                date: e.target.value
              })
            }
          />

          {/* BUTTON */}

          <button
            style={styles.button}
            onClick={sendRequest}
          >
            Send Request
          </button>

        </div>

        {/* ================= RIGHT PANEL ================= */}

        <div style={styles.card}>

          <h2 style={styles.title}>
            My Requests
          </h2>

          {requests.length === 0 && (
            <p>No Requests Found</p>
          )}

          {requests.map(req => (

            <div
              key={req._id}
              style={styles.requestCard}
            >

              {/* TOP */}

              <div style={styles.row}>

                <b>
                  {req.labourName}
                </b>

                <span
                  style={{
                    ...styles.badge,

                    background:
                      req.status === "Accepted"
                        ? "#14532d"
                        : req.status === "Rejected"
                        ? "#7f1d1d"
                        : "#1f2937"
                  }}
                >
                  {req.status}
                </span>

              </div>

              {/* DETAILS */}

              <p style={styles.text}>
                Work: {req.workType}
              </p>

              <p style={styles.text}>
                Location: {req.location}
              </p>

              <p style={styles.text}>
                Date: {req.date}
              </p>

              {/* ================= QUOTATION ================= */}

              {req.quotation &&
               req.customerDecision !== "Accepted" &&
               req.customerDecision !== "Rejected" && (

                <div style={styles.quoteBox}>

                  <p style={styles.quoteText}>
                    Quotation: ₹{req.quotation}
                  </p>

                  <div style={styles.actionButtons}>

                    <button
                      style={styles.acceptBtn}
                      onClick={() =>
                        updateDecision(
                          req._id,
                          "Accepted"
                        )
                      }
                    >
                      Accept
                    </button>

                    <button
                      style={styles.rejectBtn}
                      onClick={() =>
                        updateDecision(
                          req._id,
                          "Rejected"
                        )
                      }
                    >
                      Reject
                    </button>

                  </div>

                </div>
              )}

              {/* ================= ACCEPTED ================= */}

              {req.customerDecision === "Accepted" && (

                <div style={styles.acceptedBox}>
                  Customer Accepted Quotation
                </div>
              )}

              {/* ================= REJECTED ================= */}

              {req.customerDecision === "Rejected" && (

                <div style={styles.rejectedBox}>
                  Customer Rejected Quotation
                </div>
              )}

              {/* ================= RATING SECTION ================= */}

              {req.customerDecision === "Accepted" && (

                <div style={styles.ratingBox}>

                  {/* SHOW BEFORE SUBMIT */}

                  {!req.feedback?.rating && (

                    <>
                      <div style={styles.stars}>

                        {[1,2,3,4,5].map(star => (

                          <span
                            key={star}
                            style={{
                              fontSize: "26px",
                              cursor: "pointer",

                              color:
                                (req.tempRating || 0) >= star
                                  ? "#facc15"
                                  : "#374151"
                            }}
                            onClick={() =>

                              setRequests(prev =>
                                prev.map(r =>
                                  r._id === req._id
                                    ? {
                                        ...r,
                                        tempRating: star
                                      }
                                    : r
                                )
                              )
                            }
                          >
                            ★
                          </span>

                        ))}

                      </div>

                      <textarea
                        placeholder="Write review..."
                        style={styles.textarea}
                        value={req.tempComment || ""}
                        onChange={(e) =>

                          setRequests(prev =>
                            prev.map(r =>
                              r._id === req._id
                                ? {
                                    ...r,
                                    tempComment:
                                      e.target.value
                                  }
                                : r
                            )
                          )
                        }
                      />

                      <button
                        style={styles.button}
                        onClick={() =>
                          submitFeedback(
                            req._id,
                            req.tempRating,
                            req.tempComment
                          )
                        }
                      >
                        Submit Rating
                      </button>
                    </>
                  )}

                  {/* SHOW SAVED FEEDBACK */}

                  {req.feedback &&
                   req.feedback.rating &&
                   req.feedback.rating !== 0 && (

                    <div style={styles.saved}>

                      {/* BIG GOLD STARS */}

                      <div style={styles.goldStars}>
                        {"★".repeat(
                          Number(req.feedback.rating)
                        )}
                      </div>

                      {/* RATING */}

                      <p style={styles.savedRating}>
                        ⭐ {Number(req.feedback.rating)}/5
                      </p>

                      {/* COMMENT */}

                      <p style={styles.savedComment}>
                        {req.feedback.comment}
                      </p>

                    </div>
                  )}

                </div>
              )}

            </div>

          ))}

        </div>

      </div>
    </div>
  );
}

